# --------------------------------
# Test Generated by ChatGPT
# Setup constants
# --------------------------------
addi x1, x0, 5
addi x2, x0, 3
addi x3, x0, -1
addi x4, x0, 1

addi x31, x0, 31      # shift amount


# --------------------------------
# ADD
# 5 + 3 = 8
# --------------------------------
add x5, x1, x2        # expect 8


# --------------------------------
# SUB
# 5 - 3 = 2
# --------------------------------
sub x6, x1, x2        # expect 2


# --------------------------------
# SLL
# 5 << 3 = 40
# --------------------------------
sll x7, x1, x2        # expect 40


# --------------------------------
# SLT
# 3 < 5
# --------------------------------
slt x8, x2, x1        # expect 1


# --------------------------------
# SLTU
# 3 < 5
# --------------------------------
sltu x9, x2, x1       # expect 1


# --------------------------------
# XOR
# 5 ^ 3 = 6
# --------------------------------
xor x10, x1, x2       # expect 6


# --------------------------------
# SRL
# 40 >> 3 = 5
# --------------------------------
srl x11, x7, x2       # expect 5


# --------------------------------
# SRA (negative shift)
# -1 >> 3 = -1
# --------------------------------
sra x12, x3, x2       # expect -1


# --------------------------------
# OR
# 5 | 3 = 7
# --------------------------------
or x13, x1, x2        # expect 7


# --------------------------------
# AND
# 5 & 3 = 1
# --------------------------------
and x14, x1, x2       # expect 1


# --------------------------------
# Edge case tests
# --------------------------------

# negative arithmetic shift
addi x15, x0, 1
sll  x15, x15, x31    # x15 = 0x80000000

sra  x16, x15, x4     # expect 0xC0000000


# logical shift check
srl  x17, x15, x4     # expect 0x40000000


# signed comparison edge
addi x18, x0, -1
addi x19, x0, 1

slt  x20, x18, x19    # expect 1
sltu x21, x18, x19    # expect 0
